// Script Node - Asignar visibleKeys y mainKey según tipo de dispositivo
// Se espera un msg como el que viene en DEVICE_CREATED, con msg.type

var type = msg.type;
var visibleKeys = {};
var mainKey = null;

// Normalizar tipo
if (type && typeof type === 'string') {
    type = type.trim().toLowerCase();
} else {
    type = '';
}

// Mapa de tipos → config (visibleKeys + mainKey)
var deviceTypeMap = {
    // Ultrasonico
    'ultrasonico': {
        mainKey: 'waterLevelPerc',
        visibleKeys: {
            // data_temperature_2: { label: 'Temperatura', unit: '°C' },
            waterLevelPerc: { label: 'Nivel de agua', unit: '%' },
            waterVolume:    { label: 'Volumen de agua', unit: 'L' }
        }
    },
    // Freatimetro
    'freatimetro': {
        mainKey: 'waterDistanceFromGround',
        visibleKeys: {
            // data_temperature_2: { label: 'Temperatura', unit: '°C' },
            waterDistanceFromGround: { label: 'Profundidad de napa', unit: 'm' },
            data_Water_deep_cm:    { label: 'Nivel sobre sensor', unit: 'm' }
        }
    },

    // Tranquera
    'tranquera': {
        mainKey: 'door_state',
        visibleKeys: {
            door_state:      { label: 'Estado', unit: '' },
            last_open_ts:    { label: 'Última apertura', unit: '' },
            open_duration_s: { label: 'Duración apertura', unit: 's' }
        }
    },

    // Lanza / riego
    'lanza': {
        mainKey: 'pressure_bar',
        visibleKeys: {
            pressure_bar: { label: 'Presión', unit: 'bar' },
            flow_l_min:   { label: 'Caudal', unit: 'L/min' }
        }
    }

    // Agregá más tipos acá:
    // 'tanque': { mainKey: '...', visibleKeys: {...} },
    // 'freatimetro': { ... }
};

// Tomar config según type
if (deviceTypeMap[type]) {
    visibleKeys = deviceTypeMap[type].visibleKeys || {};
    mainKey = deviceTypeMap[type].mainKey || null;
}

// Solo mandamos los atributos que queremos persistir
msg = {
    visibleKeys: visibleKeys,
    mainKey: mainKey
};

return {
    msg: msg,
    metadata: metadata,
    msgType: "POST_ATTRIBUTES_REQUEST"
};

// Tomamos el nombre del device desde metadata (más confiable en TB)
var name = metadata.deviceName || metadata.name || msg.name;

// Valor por defecto para dispositivos a batería (LB)
var nominal = 3.6;

if (name && typeof name === 'string') {

    // Limpieza básica
    var trimmed = name.trim();

    if (trimmed.length > 0) {

        // Split del nombre según la nomenclatura definida:
        // FORMATO: <MODEL>-<SUBMODEL>-<ENERGY>-<ID>
        // Ej: DS-US2-LB-0014
        var parts = trimmed.split('-');

        // Validamos que tenga al menos 3 segmentos
        if (parts.length >= 3) {

            // Modelo del dispositivo (DS, PS, etc)
            var model = parts[0];

            // Tipo de energía (LB / LS) → SIEMPRE en posición 2 según estándar
            var energyType = parts[2];

            if (model && energyType) {

                // Normalizamos a mayúsculas para evitar errores
                model = model.toUpperCase();
                energyType = energyType.toUpperCase();

                // Generamos clave combinada para overrides específicos
                var key = model + "_" + energyType;

                // ---- TABLA DE OVERRIDES ----
                // Casos donde el comportamiento real difiere del esperado
                // Ej: DS-LB reporta ~3.3V en campo (no 3.6V)
                var overrides = {
                    "DS_LB": 3.3
                };

                // ---- LÓGICA ----

                // 1. Primero evaluamos overrides específicos
                if (overrides[key] !== undefined) {
                    nominal = overrides[key];
                }

                // 2. Si no hay override, usamos comportamiento estándar por tipo de energía
                else if (energyType === 'LS') {
                    // Nodo solar
                    nominal = 4.0;
                } else if (energyType === 'LB') {
                    // Nodo a batería
                    nominal = 3.6;
                }

                // Nota: si energyType no es LB ni LS, queda el default (3.6)
            }
        }
    }
}

// Enviamos solo el atributo necesario para no ensuciar el payload
msg = { battery_nominal: nominal };

// Persistimos como atributo del device
return { msg: msg, metadata: metadata, msgType: "POST_ATTRIBUTES_REQUEST" };
